#!/bin/bash

# Database credentials
DB_USER="backup_user"
DB_PASSWORD="BackupPass123"
DB_HOST="localhost"

# Backup directory
BACKUP_DIR="/path/to/backup/directory"

# Date and time for backup file
DATE=$(date +%Y%m%d_%H%M%S)

# Filename for the backup
FILENAME="${BACKUP_DIR}/db_backup_${DATE}.sql"

# Perform the database backup
mysqldump -h $DB_HOST -u $DB_USER -p$DB_PASSWORD --all-databases > $FILENAME

# Check if the backup was successful
if [ $? -eq 0 ]; then
    echo "Backup completed successfully: $FILENAME"
else
    echo "Backup failed!"
fi

